elFen=root.querySelector("#xq7-fen");elSide=root.querySelector("#xq7-side");elTurn=root.querySelector("#xq7-turn");elMoves=root.querySelector("#xq7-moves");elMovesLabel=root.querySelector("#xq7-moves-label");elStatus=root.querySelector("#xq7-status");elPanel=root.querySelector("#xq7-panel");elAutoModeButtons=Array.from(root.querySelectorAll("[data-auto-mode]"));

let mini=false;
