function showNotify(msg){if(cfg.showPanel===false||isGameEndPopupVisible()||isMatchmakingPopupVisible())return;document.getElementById("xq7-notify")?.remove();const n=document.createElement("div");n.id="xq7-notify";n.textContent=msg;document.body.appendChild(n);setTimeout(()=>n.remove(),3500);}
function isGameEndPopupVisible(){const re=/\\b(resigned|checkmate|victory|defeat|you win|you lose|wins|loses|draw|stalemate|review|rematch|timer expired|time expired|out of time)\\b/i;return Array.from(document.querySelectorAll(".ReactModal__Overlay,[role='dialog'],[aria-modal='true'],.modal,[class*='modal']")).filter(isVisibleElement).some(n=>{const t=(n.textContent||"").replace(/\\s+/g," ").trim();return t.length>0&&re.test(t);});}
function isMatchmakingPopupVisible(){const re=/\\b(finding you an opponent|finding opponent|searching for opponent|cancel)\\b/i;return Array.from(document.querySelectorAll(".ReactModal__Overlay,[role='dialog'],[aria-modal='true'],.modal,[class*='modal']")).filter(isVisibleElement).some(n=>{const t=(n.textContent||"").replace(/\\s+/g," ").trim();return t.length>0&&re.test(t)&&/opponent/i.test(t);});}
function hasDetectedBoard(){if(state.fen)return true;return document.querySelectorAll("div.square").length>=60&&!!choosePrimaryBoardRect();}
function shouldShowPanel(){return cfg.showPanel!==false&&!isGameEndPopupVisible()&&!isMatchmakingPopupVisible()&&hasDetectedBoard();}

function scheduleRender(){if(renderPending)return;renderPending=true;requestAnimationFrame(render);}
function render(){renderPending=false;if(!uiBuilt)buildUI();const root=document.getElementById("xq7-root");const pv=shouldShowPanel();if(root)root.style.display=pv?"":"none";if(!pv){if(isGameEndPopupVisible()||isMatchmakingPopupVisible()||!hasDetectedBoard())clearHintOverlay();document.getElementById("xq7-notify")?.remove();}else{if(elFen&&elSide&&elTurn&&elMoves&&elMovesLabel&&elStatus){if(state.myColor==="red")elSide.innerHTML='<span class="badge badge-red">RED</span>';else if(state.myColor==="black")elSide.innerHTML='<span class="badge badge-black">BLACK</span>';else elSide.textContent="Detecting...";const isMy=state.myColor&&state.turn===state.myColor;if(state.turn==="red"){const g=isMy?" myturn":"";elTurn.innerHTML='<span class="badge badge-red'+g+'">Red to move</span>'+(isMy?' <- <b style="color:#f0a500">YOUR TURN</b>':"");}else if(state.turn==="black"){const g=isMy?" myturn":"";elTurn.innerHTML='<span class="badge badge-black'+g+'">Black to move</span>'+(isMy?' <- <b style="color:#f0a500">YOUR TURN</b>':"");}else elTurn.textContent="-";if(isMy&&prevTurnForNotify!==state.turn)showNotify("Your turn");prevTurnForNotify=state.turn;elAutoModeButtons.forEach(btn=>{const ia=btn.dataset.autoMode===cfg.autoPlayMode;btn.classList.toggle("active",ia);btn.disabled=ia;});elFen.textContent=state.fen||"-";if(state.turn!==state.myColor){elMovesLabel.textContent="Waiting for opponent...";elMoves.textContent="";}else if(state.engineAnalyzing){elMovesLabel.textContent="Analyzing "+cfg.lines+" line(s)...";elMoves.textContent="";}else if(state.engineMoves.length){elMovesLabel.textContent=state.engineMoves.length+" hint(s)";elMoves.textContent=state.engineMoves.map((m,i)=>formatHintMove(m,i,state.fen)).join("\\n");}else{elMovesLabel.textContent=state.turn===state.myColor?"No hints yet":"-";elMoves.textContent="";}elStatus.textContent=state.fen?"Live DOM | "+new Date().toLocaleTimeString("en-US"):"Waiting for board...";elStatus.style.color=state.fen?"#3dc96c":"#f80";if(autoMoveError){elStatus.textContent="Auto-move error: "+autoMoveError;elStatus.style.color="#ff6b6b";}}}publishStreamState();ensureHintOverlayVisible();maybeAutoMove();}

// ── Square grid & center ──────────────────────────────────────────
function getBoardRoot(){const sqs=Array.from(document.querySelectorAll("div.square"));if(!sqs.length)return document.body;let cur=sqs[0];while(cur){if(sqs.every(sq=>cur.contains(sq)))return cur;cur=cur.parentElement;}return document.body;}
